using System;
using System.IO;

class Program
{
    static void Main(string[] args)
    {
        try
        {
            string path = "example.txt";
            string content = "Bu bir nümunə mətndir!\nİkinci sətir.");

            // Fayla mətn yazmaq
            File.WriteAllText(path, content);
            Console.WriteLine("Fayl uğurla yaradıldı və mətn yazıldı.");
        }
        catch (IOException ex)
        {
            Console.WriteLine("Səhv: Fayl yazılarkən problem yarandı.");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}
// Output:
// Fayl uğurla yaradıldı və mətn yazıldı.

