using System;
using System.IO;

class Program
{
    static void Main(string[] args)
    {
        try
        {
            string path = "lines.txt";

            // Sətir-sətir yazma
            using (StreamWriter writer = new StreamWriter(path))
            {
                writer.WriteLine("Birinci sətir.");
                writer.WriteLine("İkinci sətir.");
                writer.WriteLine("Üçüncü sətir.");
            }
            Console.WriteLine("Fayl uğurla yazıldı.");

            // Sətir-sətir oxuma
            using (StreamReader reader = new StreamReader(path))
            {
                Console.WriteLine("Faylın məzmunu:");
                string line;
                while ((line = reader.ReadLine()) != null)
                {
                    Console.WriteLine(line);
                }
            }
        }
        catch (IOException ex)
        {
            Console.WriteLine("Səhv: Fayl əməliyyatında problem yarandı.");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}
// Output:
// Fayl uğurla yazıldı.
// Faylın məzmunu:
// Birinci sətir.
// İkinci sətir.
// Üçüncü sətir.

